package everCare.appointments.services;

import com.fasterxml.jackson.databind.ObjectMapper;
import com.google.zxing.BarcodeFormat;
import com.google.zxing.MultiFormatWriter;
import com.google.zxing.WriterException;
import com.google.zxing.client.j2se.MatrixToImageWriter;
import com.google.zxing.common.BitMatrix;
import com.itextpdf.io.image.ImageData;
import com.itextpdf.io.image.ImageDataFactory;
import com.itextpdf.kernel.colors.DeviceRgb;
import com.itextpdf.kernel.pdf.PdfDocument;
import com.itextpdf.kernel.pdf.PdfWriter;
import com.itextpdf.layout.Document;
import com.itextpdf.layout.borders.Border;
import com.itextpdf.layout.borders.LeftBorder;
import com.itextpdf.layout.borders.SolidBorder;
import com.itextpdf.layout.element.*;
import com.itextpdf.layout.properties.HorizontalAlignment;
import com.itextpdf.layout.properties.TextAlignment;
import com.itextpdf.layout.properties.VerticalAlignment;
import everCare.appointments.dtos.PatientSimpleDTO;
import everCare.appointments.dtos.UserSimpleDTO;
import everCare.appointments.entities.Medicament;
import everCare.appointments.entities.Prescription;
import everCare.appointments.repositories.PrescriptionRepository;
import jakarta.persistence.EntityNotFoundException;
import lombok.RequiredArgsConstructor;
import lombok.Slf4j;
import org.springframework.stereotype.Service;

import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.HashMap;
import java.util.Map;

@Service
@RequiredArgsConstructor
@Slf4j
public class PrescriptionPdfService {

    private final PrescriptionRepository prescriptionRepository;
    private final PatientFeignClient patientFeignClient;
    private final UserFeignClient userFeignClient;
    private final ObjectMapper objectMapper;

    // Color palette
    private static final DeviceRgb TEAL = new DeviceRgb(15, 110, 86);         // #0F6E56
    private static final DeviceRgb TEAL_LIGHT = new DeviceRgb(225, 245, 238); // #E1F5EE
    private static final DeviceRgb GRAY_LIGHT = new DeviceRgb(241, 239, 232); // #F1EFE8
    private static final DeviceRgb GRAY_MID = new DeviceRgb(95, 94, 90);      // #5F5E5A

    public byte[] generatePdf(String prescriptionId) {
        log.info("Starting PDF generation for prescription ID: {}", prescriptionId);

        try {
            // Fetch prescription from database
            Prescription prescription = prescriptionRepository.findById(prescriptionId)
                    .orElseThrow(() -> new EntityNotFoundException("Prescription not found with ID: " + prescriptionId));

            // Fetch patient and doctor data via Feign
            PatientSimpleDTO patient = patientFeignClient.getPatientById(prescription.getPatient().getUserId());
            UserSimpleDTO doctor = userFeignClient.getUserById(prescription.getDoctor().getUserId());

            // Generate QR code
            byte[] qrCode = generateQrCode(prescription);

            // Generate PDF
            ByteArrayOutputStream pdfStream = new ByteArrayOutputStream();
            PdfWriter writer = new PdfWriter(pdfStream);
            PdfDocument pdfDoc = new PdfDocument(writer);
            Document doc = new Document(pdfDoc);

            // Set default font and spacing
            doc.setMargins(20, 20, 20, 20);

            // 1. Top teal accent band (7pt)
            Table accentBand = new Table(1);
            accentBand.setWidth(600);
            Cell accentCell = new Cell();
            accentCell.setHeight(7);
            accentCell.setBackgroundColor(TEAL);
            accentCell.setBorder(Border.NO_BORDER);
            accentBand.addCell(accentCell);
            doc.add(accentBand);

            // 2. Letterhead
            Table letterhead = new Table(2);
            letterhead.setWidth(600);

            Cell leftCell = new Cell();
            leftCell.setBorder(Border.NO_BORDER);
            leftCell.add(new Paragraph("EverCare Health Center")
                    .setFontSize(24)
                    .setBold()
                    .setFontColor(TEAL));
            letterhead.addCell(leftCell);

            Cell rightCell = new Cell();
            rightCell.setBorder(Border.NO_BORDER);
            rightCell.setTextAlignment(TextAlignment.RIGHT);
            rightCell.add(new Paragraph("℞")
                    .setFontSize(32)
                    .setFontColor(TEAL));
            letterhead.addCell(rightCell);

            doc.add(letterhead);

            // 3. Horizontal rule
            LineSeparator line = new LineSeparator(new SolidBorder(GRAY_MID, 0.5f));
            doc.add(line);

            // 4. Meta band (gray background)
            Table metaBand = new Table(4);
            metaBand.setWidth(600);
            metaBand.setBackgroundColor(GRAY_LIGHT);

            addMetaCell(metaBand, "Prescription ID", prescriptionId);
            addMetaCell(metaBand, "Date", formatDate(prescription.getDatePrescription()));
            addMetaCell(metaBand, "Valid Until", formatDate(prescription.getDateFin()));
            addMetaCell(metaBand, "Appointment ID",
                    prescription.getAppointment() != null ? prescription.getAppointment().getAppointmentId() : "N/A");

            doc.add(metaBand);

            // 5. Two-column block: Patient info left | Doctor info right
            Table infoBlock = new Table(2);
            infoBlock.setWidth(600);

            Cell patientInfoCell = new Cell();
            patientInfoCell.setBorder(Border.NO_BORDER);
            patientInfoCell.add(new Paragraph("PATIENT")
                    .setFontSize(11)
                    .setBold()
                    .setFontColor(TEAL));
            patientInfoCell.add(new Paragraph(patient.getName())
                    .setFontSize(10));
            patientInfoCell.add(new Paragraph(patient.getEmail())
                    .setFontSize(9)
                    .setFontColor(GRAY_MID));
            patientInfoCell.add(new Paragraph(patient.getPhone() != null ? patient.getPhone() : "")
                    .setFontSize(9)
                    .setFontColor(GRAY_MID));
            infoBlock.addCell(patientInfoCell);

            Cell doctorInfoCell = new Cell();
            doctorInfoCell.setBorder(Border.NO_BORDER);
            doctorInfoCell.add(new Paragraph("PRESCRIBER")
                    .setFontSize(11)
                    .setBold()
                    .setFontColor(TEAL));
            doctorInfoCell.add(new Paragraph(doctor.getName())
                    .setFontSize(10));
            if (doctor.getSpecialization() != null) {
                doctorInfoCell.add(new Paragraph(doctor.getSpecialization())
                        .setFontSize(9)
                        .setFontColor(GRAY_MID));
            }
            if (doctor.getMedicalLicense() != null) {
                doctorInfoCell.add(new Paragraph("License: " + doctor.getMedicalLicense())
                        .setFontSize(8)
                        .setFontColor(GRAY_MID));
            }
            infoBlock.addCell(doctorInfoCell);

            doc.add(infoBlock);
            doc.add(new Paragraph("\n"));

            // 6. Diagnosis bar (teal-light background, 3pt teal left border)
            Table diagnosisBar = new Table(1);
            diagnosisBar.setWidth(600);
            Cell diagnosisCell = new Cell();
            diagnosisCell.setBackgroundColor(TEAL_LIGHT);
            diagnosisCell.setBorderLeft(new SolidBorder(TEAL, 3));
            diagnosisCell.setBorderRight(Border.NO_BORDER);
            diagnosisCell.setBorderTop(Border.NO_BORDER);
            diagnosisCell.setBorderBottom(Border.NO_BORDER);
            diagnosisCell.add(new Paragraph("MEDICATIONS")
                    .setFontSize(11)
                    .setBold()
                    .setFontColor(TEAL));
            diagnosisBar.addCell(diagnosisCell);
            doc.add(diagnosisBar);

            // 7. Medications table
            Table medicTable = new Table(6);
            medicTable.setWidth(600);

            // Header row
            addTableHeader(medicTable, "#");
            addTableHeader(medicTable, "Medication");
            addTableHeader(medicTable, "Form & Dosage");
            addTableHeader(medicTable, "Frequency/Duration");
            addTableHeader(medicTable, "Instructions");
            addTableHeader(medicTable, "Qty");

            // Data row (single medication per prescription)
            Medicament med = prescription.getMedicament();
            int rowIndex = 1;
            addTableData(medicTable, String.valueOf(rowIndex), GRAY_LIGHT, GRAY_MID);
            addTableData(medicTable, med.getNomCommercial(), GRAY_LIGHT, GRAY_MID);
            addTableData(medicTable, (med.getForme() != null ? med.getForme() : "") + " " +
                    (med.getDosage() != null ? med.getDosage() : ""), GRAY_LIGHT, GRAY_MID);
            addTableData(medicTable,
                    (prescription.getDateDebut() != null ? "From " + formatDate(prescription.getDateDebut()) : "") +
                    (prescription.getDateFin() != null ? " to " + formatDate(prescription.getDateFin()) : ""),
                    GRAY_LIGHT, GRAY_MID);
            addTableData(medicTable, prescription.getPosologie() != null ? prescription.getPosologie() : "", GRAY_LIGHT, GRAY_MID);
            addTableData(medicTable, prescription.getInstructions() != null ? prescription.getInstructions() : "", GRAY_LIGHT, GRAY_MID);

            doc.add(medicTable);
            doc.add(new Paragraph("\n"));

            // 8. Signature area left + QR code right
            Table signatureQrTable = new Table(2);
            signatureQrTable.setWidth(600);

            Cell signatureCell = new Cell();
            signatureCell.setBorder(Border.NO_BORDER);
            signatureCell.add(new Paragraph("Doctor Signature")
                    .setFontSize(9)
                    .setFontColor(GRAY_MID));
            signatureCell.add(new Paragraph("\n\n_____________________")
                    .setFontSize(9));
            signatureQrTable.addCell(signatureCell);

            Cell qrCell = new Cell();
            qrCell.setBorder(Border.NO_BORDER);
            qrCell.setTextAlignment(TextAlignment.RIGHT);
            try {
                ImageData qrImage = ImageDataFactory.create(qrCode, ImageData.ImageType.PNG);
                Image qrImg = new Image(qrImage).scaleToFit(80, 80);
                qrCell.add(qrImg);
            } catch (IOException e) {
                log.warn("Failed to embed QR code in PDF", e);
            }
            signatureQrTable.addCell(qrCell);

            doc.add(signatureQrTable);
            doc.add(new Paragraph("\n"));

            // 9. Footer: validity date + confidentiality notice, centered, 7.5pt
            Paragraph footer = new Paragraph(
                    "Valid until " + formatDate(prescription.getDateFin()) + " | " +
                    "This document contains confidential medical information. " +
                    "Unauthorized distribution is prohibited.")
                    .setFontSize(7.5f)
                    .setTextAlignment(TextAlignment.CENTER)
                    .setFontColor(GRAY_MID);
            doc.add(footer);

            doc.close();

            log.info("PDF generation successful for prescription ID: {}", prescriptionId);
            return pdfStream.toByteArray();

        } catch (EntityNotFoundException e) {
            log.warn("Prescription not found: {}", prescriptionId);
            throw e;
        } catch (Exception e) {
            log.warn("Error generating PDF for prescription ID {}: {}", prescriptionId, e.getMessage(), e);
            throw new RuntimeException("Failed to generate PDF: " + e.getMessage(), e);
        }
    }

    private byte[] generateQrCode(Prescription prescription) throws WriterException, IOException {
        log.info("Generating QR code for prescription ID: {}", prescription.getPrescriptionId());

        // Build FHIR-lite JSON payload
        Map<String, Object> fhirPayload = new HashMap<>();
        fhirPayload.put("resourceType", "MedicationRequest");
        fhirPayload.put("id", prescription.getPrescriptionId());
        fhirPayload.put("patient", prescription.getPatient().getUserId());
        fhirPayload.put("practitioner", prescription.getDoctor().getUserId());
        fhirPayload.put("date", prescription.getDatePrescription().toString());
        fhirPayload.put("validUntil", prescription.getDateFin().toString());

        // Medications array
        Map<String, Object> medObj = new HashMap<>();
        medObj.put("name", prescription.getMedicament().getNomCommercial());
        medObj.put("dosage", prescription.getMedicament().getDosage());
        medObj.put("frequency", prescription.getPosologie());
        medObj.put("duration", prescription.getDateFin() != null ? prescription.getDateFin().toString() : "");
        fhirPayload.put("medications", new Map[]{medObj});

        // Serialize to JSON
        String jsonPayload = objectMapper.writeValueAsString(fhirPayload);

        // Generate QR code using ZXing
        MultiFormatWriter writer = new MultiFormatWriter();
        BitMatrix bitMatrix = writer.encode(jsonPayload, BarcodeFormat.QR_CODE, 300, 300);

        // Convert to PNG bytes
        ByteArrayOutputStream qrStream = new ByteArrayOutputStream();
        MatrixToImageWriter.writeToStream(bitMatrix, "PNG", qrStream);

        log.info("QR code generated successfully for prescription ID: {}", prescription.getPrescriptionId());
        return qrStream.toByteArray();
    }

    private void addMetaCell(Table table, String label, String value) {
        Cell cell = new Cell();
        cell.setBorder(Border.NO_BORDER);
        cell.add(new Paragraph(label)
                .setFontSize(8)
                .setBold()
                .setFontColor(GRAY_MID));
        cell.add(new Paragraph(value)
                .setFontSize(9));
        table.addCell(cell);
    }

    private void addTableHeader(Table table, String headerText) {
        Cell headerCell = new Cell();
        headerCell.setBackgroundColor(TEAL);
        headerCell.add(new Paragraph(headerText)
                .setFontSize(9)
                .setBold()
                .setFontColor(new DeviceRgb(255, 255, 255)));
        table.addCell(headerCell);
    }

    private void addTableData(Table table, String value, DeviceRgb bgColor, DeviceRgb textColor) {
        Cell cell = new Cell();
        cell.setBackgroundColor(bgColor);
        cell.add(new Paragraph(value)
                .setFontSize(9)
                .setFontColor(textColor));
        table.addCell(cell);
    }

    private String formatDate(LocalDate date) {
        if (date == null) {
            return "N/A";
        }
        return date.format(DateTimeFormatter.ofPattern("dd/MM/yyyy"));
    }

}

package everCare.appointments.feign;

import everCare.appointments.dtos.PatientSimpleDTO;
import org.springframework.cloud.openfeign.FeignClient;
